"use client";

import { useEffect, useState } from "react";

export default function ThemeToggle() {
  const [isDark, setIsDark] = useState(false);

  // On mount, read saved preference
  useEffect(() => {
    const saved = localStorage.getItem("cal-theme");
    const prefersDark = window.matchMedia("(prefers-color-scheme: dark)").matches;
    const shouldBeDark = saved ? saved === "dark" : prefersDark;
    setIsDark(shouldBeDark);
    document.documentElement.classList.toggle("dark", shouldBeDark);
  }, []);

  function toggle() {
    const next = !isDark;
    setIsDark(next);
    document.documentElement.classList.toggle("dark", next);
    localStorage.setItem("cal-theme", next ? "dark" : "light");
  }

  return (
    <button
      onClick={toggle}
      aria-label="Toggle theme"
      className="relative w-12 h-6 rounded-full transition-colors duration-300 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-400"
      style={{
        background: isDark
          ? "var(--cal-blue)"
          : "var(--cal-border-strong)",
      }}
    >
      {/* Track icons */}
      <span
        className="absolute inset-0 flex items-center justify-between px-1.5 text-[10px] pointer-events-none select-none"
      >
        <span>ΓÿÇ∩╕Å</span>
        <span>≡ƒîÖ</span>
      </span>

      {/* Sliding thumb */}
      <span
        className="absolute top-0.5 left-0.5 w-5 h-5 rounded-full bg-white shadow-sm transition-transform duration-300"
        style={{
          transform: isDark ? "translateX(24px)" : "translateX(0)",
        }}
      />
    </button>
  );
}

